content.css_code:
[data-timeline="1"] {
--line-color: #dbd8e0;
--line-width: 1px;
--items-space: 2.5rem;
--active-line-height: 0; /* default height of active line, should be 0 */
--number-color: var(--hcl-neutral-9);
--number-bg: var(--hcl-neutral-3);
--number-border: #dbd8e0;
--active-line-color: #598BC8;
--active-number-color: var(--hcl-neutral-1);
--active-number-bg: #598BC8;
--active-number-border: #598BC8;
--active-number-transition: 0.3s;
}

content.javascript_code:
gsap.registerPlugin(ScrollTrigger);

const timeline1 = document.querySelectorAll('[data-timeline="1"] [data-timeline="active"]');

timeline1.forEach((item, index) => {
    const timeline1Parent = item.closest('[data-timeline="1"] > div');

    // Calculate the height of the current item's parent
    const timeline1ParentHeight = timeline1Parent.clientHeight;

    gsap.fromTo(item,
        { scaleY: 0 },
        {
            scaleY: 1,
            ease: "none",
            scrollTrigger: {
                trigger: timeline1Parent,
                start: `center bottom-=20%`,
                end: `center bottom-=${20 + (timeline1ParentHeight / window.innerHeight) * 100}%`,
                scrub: true,
                onEnter: () => timeline1Parent.classList.add('active'),
                onLeaveBack: () => {
                    item.style.scaleY = 0;
                    timeline1Parent.classList.remove('active');
                }
            }
        }
    );
});
